import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

const Navigation = ({ showLogout = true }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const userRole = localStorage.getItem('role');
  const userName = localStorage.getItem('userName') || 'User';

  const handleLogout = () => {
    if (window.confirm('Are you sure you want to logout?')) {
      localStorage.clear();
      navigate('/');
    }
  };

  return (
    <div style={styles.topNav}>
      <div style={styles.navBrand}>
        <span style={styles.logo}>🎯</span> TMS
      </div>

      <div style={styles.navContent}>
        {userRole && (
          <div style={styles.userInfo}>
            <div style={styles.userName}>{userName}</div>
            <div style={styles.userRoleBadge}>
              {userRole}
            </div>
          </div>
        )}

        {showLogout && (
          <button
            onClick={handleLogout}
            style={styles.btnLogout}
            onMouseEnter={e => {
              e.target.style.background = 'linear-gradient(135deg, #dc2626, #b91c1c)';
              e.target.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={e => {
              e.target.style.background = 'linear-gradient(135deg, #ef4444, #dc2626)';
              e.target.style.transform = 'translateY(0)';
            }}
          >
            🚪 Logout
          </button>
        )}
      </div>
    </div>
  );
};

const styles = {
  topNav: {
    background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.9), rgba(30, 41, 59, 0.7))',
    backdropFilter: 'blur(15px)',
    borderBottom: '2px solid rgba(51, 65, 85, 0.5)',
    padding: '20px 40px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    position: 'sticky',
    top: 0,
    zIndex: 100,
    boxShadow: '0 10px 30px -10px rgba(0, 0, 0, 0.5)',
  },
  navBrand: {
    fontSize: '1.8rem',
    fontWeight: 800,
    background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text',
    letterSpacing: '-1px',
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
  },
  logo: {
    fontSize: '2rem',
  },
  navContent: {
    display: 'flex',
    alignItems: 'center',
    gap: '30px',
  },
  userInfo: {
    textAlign: 'right',
    paddingRight: '30px',
    borderRight: '2px solid rgba(51, 65, 85, 0.5)',
  },
  userName: {
    fontSize: '1rem',
    fontWeight: 600,
    color: '#cbd5e1',
  },
  userRoleBadge: {
    display: 'inline-block',
    background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
    color: 'white',
    padding: '6px 16px',
    borderRadius: '20px',
    fontSize: '0.75rem',
    fontWeight: 700,
    marginTop: '6px',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
    fontFamily: 'Poppins, sans-serif',
  },
  btnLogout: {
    padding: '12px 24px',
    background: 'linear-gradient(135deg, #ef4444, #dc2626)',
    color: 'white',
    border: 'none',
    borderRadius: '12px',
    fontWeight: 600,
    fontSize: '0.9rem',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    fontFamily: 'Poppins, sans-serif',
    boxShadow: '0 10px 25px -8px rgba(239, 68, 68, 0.4)',
  },
};

export default Navigation;
